### Task 2 — `public/index.html` Chat UI

**Single-file SPA** with inline `<style>` and `<script>` per the explicit "no framework" constraint. Target: dark theme, clean modern chat layout.

**DOM skeleton:**
```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Managed Agents POC</title>
  <style>
    /* dark theme: bg #0f1115, surface #1a1d24, accent #4a9eff,
       text #e6e8eb, muted #7a8290, border #2a2f3a */
    /* flex column: header | #messages (scroll) | #composer */
  </style>
</head>
<body>
  <main id="app">
    <header>Managed Agents POC</header>
    <div id="messages" aria-live="polite"></div>
    <form id="composer">
      <input id="prompt" placeholder="Ask about weather or anything else…" autocomplete="off" />
      <button id="send" type="submit">Send</button>
    </form>
  </main>
  <script>
    /* see §4.2 logic */
  </script>
</body>
</html>
```

**Client-side logic (inline script):**

```js
const messages = document.getElementById("messages");
const form = document.getElementById("composer");
const input = document.getElementById("prompt");
const sendBtn = document.getElementById("send");

function renderMessage({ role, text, agentType }) {
  const el = document.createElement("div");
  el.className = `msg msg-${role}`;
  if (agentType && role === "assistant") {
    const badge = document.createElement("div");
    badge.className = "badge";
    badge.textContent = agentType === "weather" ? "weather-agent"
                      : agentType === "research" ? "research-agent"
                      : "default (research)";
    el.appendChild(badge);
  }
  const body = document.createElement("div");
  body.className = "body";
  body.textContent = text; // textContent, NOT innerHTML — XSS guard
  el.appendChild(body);
  messages.appendChild(el);
  messages.scrollTop = messages.scrollHeight;
}

function renderLoading() {
  const el = document.createElement("div");
  el.className = "msg msg-assistant loading";
  el.id = "pending";
  el.textContent = "Thinking…";
  messages.appendChild(el);
  messages.scrollTop = messages.scrollHeight;
}

async function submitPrompt(prompt) {
  if (!prompt.trim()) return;
  renderMessage({ role: "user", text: prompt });
  input.value = "";
  input.disabled = true;
  sendBtn.disabled = true;
  renderLoading();

  try {
    const resp = await fetch("/api/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ prompt }),
    });
    const data = await resp.json();
    document.getElementById("pending")?.remove();

    if (!resp.ok) {
      renderMessage({ role: "error", text: data.error || "Request failed." });
    } else {
      renderMessage({ role: "assistant", text: data.response, agentType: data.agentType });
    }
  } catch (err) {
    document.getElementById("pending")?.remove();
    renderMessage({ role: "error", text: String(err) });
  } finally {
    input.disabled = false;
    sendBtn.disabled = false;
    input.focus();
  }
}

form.addEventListener("submit", (e) => {
  e.preventDefault();
  submitPrompt(input.value);
});
```

**Key implementation decisions:**
- **`textContent` everywhere** — not `innerHTML`. The agent response may contain `<`, `&`, backticks, etc. This single rule prevents XSS even though the POC is localhost-only (good habit).
- **Loading indicator** — inserted as a placeholder assistant bubble with id `pending`, replaced on response. Simpler than maintaining a separate spinner element.
- **Disable input during request** — prevents double-submit and makes the pending state obvious.
- **`aria-live="polite"`** on `#messages` — free accessibility win.
- **No markdown rendering** — POC ships plain text. Agents return plain text today; a markdown library is premature.

**Styling targets** (inline CSS sketch):
- Background `#0f1115`, message area `#1a1d24`, input surface `#13161c`
- User bubble right-aligned, accent-bordered; assistant bubble left-aligned, neutral
- Routing badge: small `font-size: 11px`, muted color, above assistant body
- Responsive: single-column, max-width 800px, centered
- System font stack (no web fonts — POC constraint)

**Files touched (Task 2):** `public/index.html` (new, ~120 LOC).

