### Task 2 — `src/agent/runAgent.ts`

**Implementation shape:**
```ts
import { anthropic } from "../config/anthropic";
import { ConversationState } from "../data/conversationState";
import { SYSTEM_PROMPT } from "../data/prompts";
import { TOOLS } from "../data/tools";
import { dispatchTool } from "./toolDispatcher";

const MODEL = "claude-sonnet-4-5";
const MAX_TOKENS = 1024;

export async function runAgent(userPrompt: string): Promise<string> {
  const state = new ConversationState();
  state.addUserMessage(userPrompt);

  while (true) {
    const response = await anthropic.messages.create({
      model: MODEL,
      max_tokens: MAX_TOKENS,
      system: SYSTEM_PROMPT,
      tools: TOOLS,
      messages: state.getMessages(),
    });

    state.addAssistantMessage(response.content);

    if (response.stop_reason === "end_turn") {
      return response.content
        .filter((b): b is Anthropic.TextBlock => b.type === "text")
        .map((b) => b.text)
        .join("\n");
    }

    if (response.stop_reason === "tool_use") {
      for (const block of response.content) {
        if (block.type !== "tool_use") continue;
        const result = dispatchTool(
          block.name,
          block.input as Record<string, unknown>
        );
        state.addToolResult(block.id, result);
      }
      continue;
    }

    // Any other stop_reason (max_tokens, stop_sequence) is unexpected for POC
    throw new Error(`Unexpected stop_reason: ${response.stop_reason}`);
  }
}
```

**Key architectural decisions:**

1. **Loop shape**: `while (true)` with explicit `return` on `end_turn` matches the quickstart pattern and keeps control flow linear.
2. **Tool-use handling**: Iterate *all* `tool_use` blocks in a single assistant response before sending tool_results — the API may emit multiple parallel tool calls, and all of them must be satisfied in the next user message.
3. **Text aggregation**: Join with `\n` (not `""`) — Claude occasionally emits multiple text blocks separated by tool_use; newline join preserves readability.
4. **Fail-fast on unexpected stop_reasons**: Even though the POC is happy-path, `max_tokens` exhaustion silently returning garbage would be confusing. An explicit throw surfaces issues during demo.
5. **Type narrowing**: Use the SDK's discriminated union on `block.type`. `block.input` comes back as `unknown` and needs an `as` cast to satisfy the dispatcher signature.
6. **Import `Anthropic` as a type** for the `TextBlock` filter (namespace import from SDK), consistent with how `conversationState.ts` does it.

**Estimated complexity:** Medium (~50 LOC, 45 min including debugging).

